// // This module implements a 4-bit shift register that shifts right on the rising edge of the clock and feeds the serial input into the most significant bit (MSB). It also has a reset input to clear its contents.
module shift_register (
    input clk,
    input reset,
    input serial_in,
    output reg [3:0] shift_reg
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            shift_reg <= 4'b0000;
        end else begin
            shift_reg <= {shift_reg[2:0], serial_in};
        end
    end
endmodule
